## Clara Tool - Qualificar Lead v2

Atualiza 29 campos + tags + pipeline no GHL.

**Input:** { phone, tags, campos, nome_contato, empresa }
**Output:** { resultado, contact_id, sucesso }

parameters.jsCode:
// Validate input + unwrap $fromAI query fields
// n8n LangChain toolWorkflow puts $fromAI fields inside "query" object
// while static expressions stay at top level
const raw = $input.first().json;

// Merge query fields into top level
const query = raw.query || {};
const input = { ...raw };

// Unwrap query fields (AI-generated via $fromAI)
if (typeof query === 'object' && query !== null) {
  for (const [key, value] of Object.entries(query)) {
    if (key !== 'phone' && input[key] === undefined) {
      input[key] = value;
    }
  }
}
delete input.query;

// Validate phone
const phone = input.phone || '';
if (!phone || phone.trim() === '') {
  return [{ json: { resultado: 'Erro: telefone do lead não fornecido.', sucesso: false } }];
}

// Clean phone (remove non-digits, keep +)
input.phone = phone.replace(/[^\d+]/g, '');

return [{ json: input }];

