  if (input.campos) {
    try {
      const campos = typeof input.campos === 'string' ? JSON.parse(input.campos) : input.campos;
      const customFields = [];

      for (const [key, value] of Object.entries(campos)) {
        if (value === null || value === undefined || value === '') continue;

        // Resolve key to field ID
